+            }
+          }
+        }
+      } catch (err) {
+        logger.error('Poll error:', err);
+      }
+
+      await new Promise(r => setTimeout(r, POLL_INTERVAL));
+    }
+  }
+
+  async _process(task) {
+    try {
+      await db.query("UPDATE task_queue SET status = 'processing' WHERE id = $1", [task.id]);
+      const result = await executeTask(task);
+      await db.query("UPDATE task_queue SET status = 'completed', result = $1 WHERE id = $2", [JSON.stringify(result), task.id]);
+      logger.info('Task completed', { taskId: task.id });
