+      await db.query("UPDATE task_queue SET status = 'failed', error = $1 WHERE id = $2", [err.message, task.id]);
+      logger.error('Task failed', { taskId: task.id, error: err.message });
+    } finally {
+      this.activeTasks--;
+      this.taskIds.delete(task.id);
+    }
