use std::fmt;

enum JsonValue {
    Null,
    Bool(bool),
    Number(f64),
    Str(String),
    Array(Vec<JsonValue>),
    Object(Vec<(String, JsonValue)>),
}

impl fmt::Display for JsonValue {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            JsonValue::Null => write!(f, "null"),
            JsonValue::Bool(b) => write!(f, "{}", b),
            JsonValue::Number(n) => write!(f, "{}", n),
            JsonValue::Str(s) => {
                let escaped = s.replace('\\', "\\\\").replace('"', "\\\"").replace('\n', "\\n").replace('\t', "\\t");
                write!(f, "\"{}\"", escaped)
            }
            JsonValue::Array(arr) => {
                write!(f, "[")?;
                for (i, item) in arr.iter().enumerate() {
                    if i > 0 { write!(f, ", ")?; }
                    write!(f, "{}", item)?;
                }
                write!(f, "]")
            }
            JsonValue::Object(obj) => {
                write!(f, "{{")?;
                for (i, (key, value)) in obj.iter().enumerate() {
                    if i > 0 { write!(f, ", ")?; }
                    write!(f, "\"{}\": {}", key, value)?;
                }
                write!(f, "}}")
            }
        }
    }
}

fn serialize_json(value: &JsonValue) -> String {
    format!("{}", value)
}

fn main() {
    let json = JsonValue::Object(vec![
        ("name".to_string(), JsonValue::Str("Paloma".to_string())),
        ("version".to_string(), JsonValue::Number(2.5)),
        ("active".to_string(), JsonValue::Bool(true)),
        ("metadata".to_string(), JsonValue::Null),
        (
            "tags".to_string(),
            JsonValue::Array(vec![
                JsonValue::Str("ai".to_string()),
                JsonValue::Str("assistant".to_string()),
            ]),
        ),
        (
            "config".to_string(),
            JsonValue::Object(vec![
                ("nested".to_string(), JsonValue::Bool(true)),
                (
                    "path".to_string(),
                    JsonValue::Str(r"C:\\Users\\test".to_string()),
                ),
            ]),
        ),
    ]);

    println!("{}", serialize_json(&json));
}
