// Broadcast function to send messages to all open WebSocket clients
function broadcast(msg) {
    const jsonMsg = JSON.stringify(msg);
    wss.clients.forEach(client => {
        if (client.readyState === 1) { // Ensure client is ready and open
            client.send(jsonMsg);
        }
    });
}

// Send a message to the originating WebSocket client or fall back to broadcast
function sendToOrigin(cliRequestId, msg) {
    const wsClient = cliRequestToWs.get(cliRequestId);
    if (wsClient && wsClient.readyState === 1) { // Check if client exists and is open
        wsClient.send(JSON.stringify(msg));
    } else {
        broadcast(msg); // Fallback to broadcasting the message
    }
}

// Interval function to clean up stale requests in pending maps
function cleanupStaleRequests() {
    const now = Date.now();
    for (const [id, entry] of pendingAskUser.entries()) {
        if (now - entry.createdAt > PENDING_TIMEOUT_MS) {
            entry.resolve('Request timed out');
            pendingAskUser.delete(id);
        }
    }
    for (const [id, entry] of pendingToolConfirm.entries()) {
        if (now - entry.createdAt > PENDING_TIMEOUT_MS) {
            entry.resolve('Request timed out');
            pendingToolConfirm.delete(id);
        }
    }
}

// Set up interval to run the cleanup function every 60 seconds
setInterval(cleanupStaleRequests, 60 * 1000);
