// Global flag to track if embeddings are ready
let embeddingReady = false;

/**
 * Computes cosine similarity between two vectors
 * @param {number[]} a - First vector
 * @param {number[]} b - Second vector
 * @returns {number} Cosine similarity between -1 and 1
 */
export function cosineSimilarity(a, b) {
  // Handle edge cases
  if (!a || !b || a.length === 0 || b.length === 0) {
    return 0;
  }

  if (a.length !== b.length) {
    throw new Error('Vectors must have the same dimension');
  }

  let dotProduct = 0;
  let magnitudeA = 0;
  let magnitudeB = 0;

  for (let i = 0; i < a.length; i++) {
    dotProduct += a[i] * b[i];
    magnitudeA += a[i] * a[i];
    magnitudeB += b[i] * b[i];
  }

  // Handle zero vectors
  if (magnitudeA === 0 || magnitudeB === 0) {
    return 0;
  }

  const similarity = dotProduct / (Math.sqrt(magnitudeA) * Math.sqrt(magnitudeB));

  // Clamp to [-1, 1] to handle floating point precision issues
  return Math.max(-1, Math.min(1, similarity));
}

/**
 * Embeds text using Ollama API or falls back to keyword search
 * @param {string} text - Text to embed
 * @returns {Promise<number[] | null>} Embedding vector or null if unavailable
 */
export async function embed(text) {
  // Check if embeddings are ready
  if (!embeddingReady) {
    return null;
  }

  try {
    const response = await fetch('http://localhost:11434/api/embed', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({
        model: 'nomic-embed-text',
        input: text
      })
    });

    if (!response.ok) {
      console.warn(`Embedding API failed with status ${response.status}`);
      return null;
    }

    const data = await response.json();

    // Handle case where embeddings might be missing or malformed
    if (!data.embeddings || !Array.isArray(data.embeddings) || data.embeddings.length === 0) {
      console.warn('No embeddings returned from API');
      return null;
    }

    const embedding = data.embeddings[0];

    // Validate that the embedding is a valid array of numbers
    if (!Array.isArray(embedding)) {
      console.warn('Invalid embedding format');
      return null;
    }

    return embedding;
  } catch (error) {
    console.error('Failed to embed text:', error);
    return null;
  }
}

/**
 * Finds similar memories to the query
 * @param {string} query - Query text
 * @param {Array} memories - Array of memory objects with 'embedding' and 'content' fields
 * @param {number} topK - Number of top results to return
 * @returns {Promise<Array>} Top K similar memories
 */
export async function findSimilar(query, memories, topK = 5) {
  // Embed the query
  const queryEmbedding = await embed(query);

  if (queryEmbedding !== null && memories && memories.length > 0) {
    // Use vector similarity
    const results = memories.map(memory => {
      if (!memory.embedding || !Array.isArray(memory.embedding)) {
        return { memory, similarity: -1 }; // Invalid embedding gets lowest score
      }

      try {
        const similarity = cosineSimilarity(queryEmbedding, memory.embedding);
        return { memory, similarity };
      } catch (error) {
        console.warn('Error computing similarity:', error);
        return { memory, similarity: -1 };
      }
    });

    // Sort by similarity (descending) and take top K
    return results
      .filter(result => result.similarity > -1)
      .sort((a, b) => b.similarity - a.similarity)
      .slice(0, topK)
      .map(result => result.memory);
  } else {
    // Fallback to keyword search
    if (!memories || memories.length === 0) {
      return [];
    }

    const queryLower = query.toLowerCase();
    const results = memories.map(memory => {
      const contentLower = memory.content?.toLowerCase() || '';
      // Simple substring matching score (can be enhanced)
      const matchCount = (contentLower.match(new RegExp(queryLower, 'g')) || []).length;
      return { memory, similarity: matchCount };
    });

    return results
      .filter(result => result.similarity > 0)
      .sort((a, b) => b.similarity - a.similarity)
      .slice(0, topK)
      .map(result => result.memory);
  }
}

/**
 * Initialize the embedding system
 * @returns {Promise<void>}
 */
export async function initEmbeddingSystem() {
  try {
    // Test if Ollama is reachable
    const response = await fetch('http://localhost:11434/api/tags', {
      method: 'GET'
    });

    if (response.ok) {
      embeddingReady = true;
      console.log('Embedding system initialized successfully');
    } else {
      console.warn('Ollama not reachable, falling back to keyword search');
      embeddingReady = false;
    }
  } catch (error) {
    console.warn('Failed to initialize embedding system:', error);
    embeddingReady = false;
  }
}
