```javascript
function deepMerge(target, ...sources) {
  // Create a deep copy of the target to avoid mutating the original
  const result = deepClone(target);

  // Merge each source into the result
  for (const source of sources) {
    if (source === null || typeof source !== 'object') {
      continue;
    }

    for (const key in source) {
      if (source[key] === null || typeof source[key] !== 'object') {
        // For primitives or null/undefined, overwrite directly
        result[key] = source[key];
      } else if (Array.isArray(source[key])) {
        // For arrays, concatenate with existing array or create new one
        if (Array.isArray(result[key])) {
          result[key] = result[key].concat(source[key]);
        } else {
          result[key] = [...source[key]];
        }
      } else {
        // For objects, recursively merge
        if (result[key] && typeof result[key] === 'object' && !Array.isArray(result[key])) {
          result[key] = deepMerge(result[key], source[key]);
        } else {
          result[key] = deepClone(source[key]);
        }
      }
    }
  }

  return result;
}

function deepClone(obj) {
  if (obj === null || typeof obj !== 'object') {
    return obj;
  }

  if (Array.isArray(obj)) {
    return obj.map(item => deepClone(item));
  }

  const clonedObj = {};
  for (const key in obj) {
    if (obj.hasOwnProperty(key)) {
      clonedObj[key] = deepClone(obj[key]);
    }
  }

  return clonedObj;
}

