```rust
use std::fmt::Display;

#[derive(Debug, Clone)]
pub struct Stack<T> {
    items: Vec<T>,
}

impl<T> Stack<T> {
    /// Create a new empty stack
    pub fn new() -> Stack<T> {
        Stack { items: Vec::new() }
    }

    /// Push an item onto the stack
    pub fn push(&mut self, item: T) {
        self.items.push(item);
    }

    /// Remove and return the top item
    pub fn pop(&mut self) -> Option<T> {
        self.items.pop()
    }

    /// Return a reference to the top item without removing it
    pub fn peek(&self) -> Option<&T> {
        self.items.last()
    }

    /// Check if the stack is empty
    pub fn is_empty(&self) -> bool {
        self.items.is_empty()
    }

    /// Return the number of elements
    pub fn len(&self) -> usize {
        self.items.len()
    }
}

impl<T: Display> Display for Stack<T> {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        let mut items_str = Vec::new();
        for item in self.items.iter().rev() {
            items_str.push(format!("{}", item));
        }
        write!(f, "{}", items_str.join(" -> "))
    }
}

fn main() {
    // Demonstrate with integers
    println!("=== Integer Stack ===");
    let mut int_stack = Stack::new();

    println!("Is empty: {}", int_stack.is_empty());
    println!("Length: {}", int_stack.len());

    int_stack.push(1);
    int_stack.push(2);
    int_stack.push(3);

    println!("Stack after pushing 1, 2, 3: {}", int_stack);
    println!("Length: {}", int_stack.len());

    println!("Peek: {:?}", int_stack.peek());
    println!("Stack after peek: {}", int_stack);

    println!("Popped: {:?}", int_stack.pop());
    println!("Stack after pop: {}", int_stack);

    println!("Popped: {:?}", int_stack.pop());
    println!("Stack after pop: {}", int_stack);

    println!("Popped: {:?}", int_stack.pop());
    println!("Stack after pop: {}", int_stack);
    println!("Is empty: {}", int_stack.is_empty());

    // Demonstrate with strings
    println!("\n=== String Stack ===");
    let mut string_stack = Stack::new();

    string_stack.push("Hello".to_string());
    string_stack.push("World".to_string());
    string_stack.push("Rust".to_string());

    println!("Stack after pushing strings: {}", string_stack);

    while let Some(item) = string_stack.pop() {
        println!("Popped: {}", item);
    }

    println!("Is empty: {}", string_stack.is_empty());
}
