```javascript
import { ref, computed, watch } from 'vue'

const _saved = import.meta.hot ? window.__PALOMA_NOTIFICATIONS__ : undefined

const notifications = ref(_saved?.notifications ?? [])

if (import.meta.hot) {
  const save = () => {
    window.__PALOMA_NOTIFICATIONS__ = {
      notifications: notifications.value
    }
  }

  save()
  watch([notifications], save, { flush: 'sync' })
}

export function useNotifications() {
  return {
    notifications,
    unreadCount: computed(() => notifications.value.filter(n => !n.dismissed).length),
    addNotification(message, type) {
      const id = Date.now().toString()
      notifications.value.push({ id, message, type, dismissed: false })
    },
    dismiss(id) {
      const notification = notifications.value.find(n => n.id === id)
      if (notification) {
        notification.dismissed = true
      }
    }
  }
}
```

